1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteInput {
13	  customer: Customer;
14	  items: Item[];
15	}
16	
17	export interface QuoteContext {
18	  isFollowUp?: boolean;
19	}
20	
21	export interface Damage {
22	  itemType: string;
23	  amount: number;
24	}
25	
26	export interface Incident {
27	  cause: string;
28	  damages: Damage[];
29	}
30	
31	export interface Policy {
32	  items: Item[];
33	  remainingCap: number;
34	}
35	
36	export interface ClaimResult {
37	  payout: number;
38	  remainingCap: number;
39	}
40	
41	const PROCESSING_FEE = 5;
42	const BLOCK_SIZE = 3;
43	const COMPONENT_UNIT_PREMIUM = 25;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	const FIRST_INSURANCE_RATE = 0.1;
46	const LOYALTY_RATE = 0.2;
47	const LOYALTY_MIN_YEARS = 2;
48	const FOLLOW_UP_RATE = 0.15;
49	const CURSE_SURCHARGE_RATE = 0.5;
50	const HIGH_ENCHANTMENT_RATE = 0.3;
51	const HIGH_ENCHANTMENT_THRESHOLD = 5;
52	const DEDUCTIBLE = 100;
53	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
54	const DAMAGE_REIMBURSEMENT_RATE = 0.5;
55	
56	const CAP_MULTIPLIER = 2;
57	const COMPONENT_INSURANCE_VALUE = 250;
58	
59	const COMPONENT_TYPES = ["rune", "moonstone"];
60	
61	const BASE_PREMIUMS: Record<string, number> = {
62	  sword: 100,
63	  amulet: 60,
64	  staff: 80,
65	  potion: 40,
66	  rune: COMPONENT_UNIT_PREMIUM,
67	  moonstone: COMPONENT_UNIT_PREMIUM,
68	};
69	
70	const INSURANCE_VALUES: Record<string, number> = {
71	  sword: 1000,
72	  amulet: 600,
73	  staff: 800,
74	  potion: 400,
75	  rune: COMPONENT_INSURANCE_VALUE,
76	  moonstone: COMPONENT_INSURANCE_VALUE,
77	};
78	
79	const lookupByType = (table: Record<string, number>, item: Item): number =>
80	  table[item.type] ?? 0;
81	
82	const insuranceValueFor = (item: Item): number =>
83	  lookupByType(INSURANCE_VALUES, item);
84	
85	const insuranceSum = (items: Item[]): number =>
86	  sumOver(items, insuranceValueFor);
87	
88	const policyCap = (items: Item[]): number => CAP_MULTIPLIER * insuranceSum(items);
89	
90	export const buildPolicy = (items: Item[]): Policy => ({
91	  items,
92	  remainingCap: policyCap(items),
93	});
94	
95	const isComponent = (item: Item): boolean =>
96	  COMPONENT_TYPES.includes(item.type);
97	
98	const isMainItem = (item: Item): boolean => !isComponent(item);
99	
100	const unitPriceFor = (item: Item): number =>
101	  lookupByType(BASE_PREMIUMS, item);
102	
103	const sumOver = (items: Item[], valueOf: (item: Item) => number): number =>
104	  items.reduce((sum, item) => sum + valueOf(item), 0);
105	
106	const componentGroupPremium = (count: number): number =>
107	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
108	
109	const countByType = (items: Item[]): Map<string, number> =>
110	  items.reduce((counts, item) => {
111	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
112	    return counts;
113	  }, new Map<string, number>());
114	
115	const componentsBasePremium = (items: Item[]): number =>
116	  [...countByType(items.filter(isComponent)).values()].reduce(
117	    (sum, count) => sum + componentGroupPremium(count),
118	    0
119	  );
120	
121	const mainItemsBasePremium = (items: Item[]): number =>
122	  sumOver(items.filter(isMainItem), unitPriceFor);
123	
124	const totalBasePremium = (items: Item[]): number =>
125	  mainItemsBasePremium(items) + componentsBasePremium(items);
126	
127	const isHighlyEnchanted = (item: Item): boolean =>
128	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
129	
130	const itemSurchargeRate = (item: Item): number =>
131	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
132	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
133	
134	const itemSurcharges = (item: Item): number =>
135	  unitPriceFor(item) * itemSurchargeRate(item);
136	
137	const totalSurcharges = (items: Item[]): number =>
138	  sumOver(items, itemSurcharges);
139	
140	const firstInsuranceSurcharge = (policyBase: number): number =>
141	  policyBase * FIRST_INSURANCE_RATE;
142	
143	const isLoyal = (customer: Customer): boolean =>
144	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
145	
146	const policyBaseShareWhen = (
147	  policyBase: number,
148	  applies: boolean,
149	  rate: number
150	): number => (applies ? policyBase * rate : 0);
151	
152	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
153	  policyBaseShareWhen(policyBase, isLoyal(customer), LOYALTY_RATE);
154	
155	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
156	  policyBaseShareWhen(policyBase, isFollowUp, FOLLOW_UP_RATE);
157	
158	const policyWideAdjustment = (
159	  policyBase: number,
160	  customer: Customer,
161	  isFollowUp: boolean
162	): number =>
163	  firstInsuranceSurcharge(policyBase) -
164	  loyaltyDiscount(policyBase, customer) -
165	  followUpDiscount(policyBase, isFollowUp);
166	
167	const roundPremiumInMHPCOsFavor = (premium: number): number =>
168	  Math.ceil(premium);
169	
170	export const quote = (input: QuoteInput, context: QuoteContext = {}): number => {
171	  const policyBase = totalBasePremium(input.items);
172	  const premiumBeforeFee =
173	    policyBase +
174	    totalSurcharges(input.items) +
175	    policyWideAdjustment(policyBase, input.customer, context.isFollowUp ?? false);
176	  return roundPremiumInMHPCOsFavor(premiumBeforeFee + PROCESSING_FEE);
177	};
178	
179	const isHighEnchantmentClaim = (item: Item): boolean =>
180	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
181	
182	const reimbursedAmount = (item: Item, amount: number): number =>
183	  isHighEnchantmentClaim(item) ? amount * DAMAGE_REIMBURSEMENT_RATE : amount;
184	
185	const damagePayout = (item: Item, damage: Damage): number =>
186	  Math.max(0, reimbursedAmount(item, damage.amount) - DEDUCTIBLE);
187	
188	const damagedItem = (items: Item[], damage: Damage): Item | undefined =>
189	  items.find((item) => item.type === damage.itemType);
190	
191	const totalPayout = (policy: Policy, damages: Damage[]): number =>
192	  damages.reduce((sum, damage) => {
193	    const item = damagedItem(policy.items, damage);
194	    return sum + (item ? damagePayout(item, damage) : 0);
195	  }, 0);
196	
197	const roundPayoutInMHPCOsFavor = (payout: number): number => Math.floor(payout);
198	
199	export const claim = (policy: Policy, incident: Incident): ClaimResult => {
200	  const desiredPayout = totalPayout(policy, incident.damages);
201	  const payout = roundPayoutInMHPCOsFavor(
202	    Math.min(desiredPayout, policy.remainingCap)
203	  );
204	  return { payout, remainingCap: policy.remainingCap - payout };
205	};
